"use client";

import * as React from "react";
import {
  ListCard,
  Badge,
  Tag,
  Icon,
  SearchInput,
  Select,
  ToggleGroup,
  ToggleGroupItem,
  EmptyState,
  Card,
  AspectRatio,
  Separator,
} from "@gunjo/ui";
import {
  IconMapPin,
  IconMap2,
  IconWalk,
  IconSearch,
  IconArrowNarrowRight,
  IconWheelchair,
  IconDoorExit,
} from "@tabler/icons-react";
import {
  CATEGORIES,
  FLOORS,
  FACILITIES,
  STATION,
  EXIT_GUIDE,
  type CategoryId,
  type FloorId,
  type GateSide,
  type Facility,
} from "./data";
import { CATEGORY_ICON, KIND_ICON } from "./icons";
import { FacilityDetailSheet } from "./FacilityDetailSheet";

type GateFilter = "all" | GateSide;

function gateLabel(side: GateSide) {
  return side === "inside" ? "改札内" : "改札外";
}

/** ロッカーの空き総数 → 状態バッジ */
function lockerStatus(f: Facility): React.ReactNode {
  const free = f.locker?.reduce((s, l) => s + l.free, 0) ?? 0;
  if (free === 0) return <Badge variant="destructive">満</Badge>;
  if (free <= 5) return <Badge variant="warning">残りわずか</Badge>;
  return <Badge variant="success">空きあり</Badge>;
}

/** 店舗 → 営業中 / 時短 バッジ */
function shopStatus(f: Facility): React.ReactNode {
  if (f.open === undefined) return null;
  return f.open ? (
    <Badge variant="success">営業中</Badge>
  ) : (
    <Badge variant="warning">時短営業</Badge>
  );
}

function statusFor(f: Facility): React.ReactNode {
  if (f.locker) return lockerStatus(f);
  if (f.category === "shop") return shopStatus(f);
  if (f.stepFree)
    return (
      <Badge variant="info" icon={<IconWheelchair className="size-3" />}>
        対応
      </Badge>
    );
  return null;
}

export default function StationGuidePage() {
  const [category, setCategory] = React.useState<CategoryId>("all");
  const [floor, setFloor] = React.useState<FloorId | "all">("all");
  const [gate, setGate] = React.useState<GateFilter>("all");
  const [query, setQuery] = React.useState("");
  const [selected, setSelected] = React.useState<Facility | null>(null);
  const [sheetOpen, setSheetOpen] = React.useState(false);

  const results = React.useMemo(() => {
    const q = query.trim();
    return FACILITIES.filter((f) => {
      if (category !== "all" && f.category !== category) return false;
      if (floor !== "all" && f.floor !== floor) return false;
      if (gate !== "all" && f.gateSide !== gate) return false;
      if (q) {
        const hay = `${f.name} ${f.location} ${f.genre ?? ""} ${f.landmark ?? ""}`;
        if (!hay.includes(q)) return false;
      }
      return true;
    });
  }, [category, floor, gate, query]);

  const openFacility = React.useCallback((f: Facility) => {
    setSelected(f);
    setSheetOpen(true);
  }, []);

  return (
    <main className="mx-auto w-full max-w-md bg-background pb-12">
      {/* ── アプリバー ─────────────────────────────── */}
      <header className="sticky top-0 z-10 border-b bg-background/95 px-4 py-3 backdrop-blur supports-[backdrop-filter]:bg-background/80">
        <div className="flex items-center gap-2">
          <span
            className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-primary-strong text-primary-strong-foreground"
            aria-hidden="true"
          >
            <Icon icon={IconMapPin} size="md" />
          </span>
          <div className="min-w-0 flex-1">
            <h1 className="truncate text-base font-bold leading-tight text-foreground">
              駅構内ナビ
            </h1>
            <p className="truncate text-xs text-muted-foreground">{STATION.lines}</p>
          </div>
        </div>

        {/* 駅の選択 */}
        <div className="mt-3">
          <Select
            aria-label="駅を選択"
            value={STATION.name}
            onChange={() => {}}
          >
            <option value="東京駅">東京駅</option>
            <option value="新宿駅">新宿駅</option>
            <option value="品川駅">品川駅</option>
          </Select>
        </div>

        {/* 施設の検索 */}
        <div className="mt-2">
          <SearchInput
            value={query}
            onValueChange={setQuery}
            placeholder="施設・出口・店舗を検索"
            aria-label="施設を検索"
          />
        </div>
      </header>

      {/* ── 施設カテゴリ nav（横スクロール） ───────── */}
      <nav aria-label="施設カテゴリ" className="border-b bg-background px-4 py-2.5">
        <div className="-mx-4 overflow-x-auto px-4 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden">
          <ToggleGroup
            type="single"
            value={category}
            onValueChange={(v) => v && setCategory(v as CategoryId)}
            variant="outline"
            disallowEmpty
            className="w-max justify-start gap-1.5"
          >
            {CATEGORIES.map((c) => {
              const Glyph = c.id === "all" ? null : CATEGORY_ICON[c.id];
              return (
                <ToggleGroupItem
                  key={c.id}
                  value={c.id}
                  aria-label={c.label}
                  className="h-10 shrink-0 gap-1.5 whitespace-nowrap px-3"
                >
                  {Glyph && <Icon icon={Glyph} size="sm" />}
                  {c.label}
                </ToggleGroupItem>
              );
            })}
          </ToggleGroup>
        </div>
      </nav>

      {/* ── フロア / 改札 フィルタ ─────────────────── */}
      <div className="flex items-center gap-2 overflow-x-auto px-4 py-2.5 [scrollbar-width:none] [&::-webkit-scrollbar]:hidden">
        <span className="shrink-0 text-xs text-muted-foreground">フロア</span>
        <ToggleGroup
          type="single"
          value={floor}
          onValueChange={(v) => v && setFloor(v as FloorId | "all")}
          variant="outline"
          disallowEmpty
          size="sm"
          className="shrink-0 gap-1"
        >
          <ToggleGroupItem value="all" className="shrink-0">
            全て
          </ToggleGroupItem>
          {FLOORS.map((fl) => (
            <ToggleGroupItem key={fl.id} value={fl.id} className="shrink-0">
              {fl.label}
            </ToggleGroupItem>
          ))}
        </ToggleGroup>

        <Separator orientation="vertical" className="h-5 shrink-0" />

        <span className="shrink-0 text-xs text-muted-foreground">改札</span>
        <ToggleGroup
          type="single"
          value={gate}
          onValueChange={(v) => v && setGate(v as GateFilter)}
          variant="outline"
          disallowEmpty
          size="sm"
          className="shrink-0 gap-1"
        >
          <ToggleGroupItem value="all" className="shrink-0">
            全て
          </ToggleGroupItem>
          <ToggleGroupItem value="inside" className="shrink-0">
            改札内
          </ToggleGroupItem>
          <ToggleGroupItem value="outside" className="shrink-0">
            改札外
          </ToggleGroupItem>
        </ToggleGroup>
      </div>

      {/* ── 出口案内（行き先 → 最寄り出口）────────── */}
      {(category === "all" || category === "exit") && !query && (
        <section aria-label="出口案内" className="px-4 pb-1 pt-2">
          <Card className="bg-muted/30 p-3">
            <div className="mb-2 flex items-center gap-1.5">
              <IconDoorExit className="size-4 text-muted-foreground" aria-hidden="true" />
              <h2 className="text-sm font-semibold text-foreground">
                行き先から出口をさがす
              </h2>
            </div>
            <ul className="space-y-1.5">
              {EXIT_GUIDE.map((g) => {
                const f = FACILITIES.find((x) => x.id === g.facilityId);
                return (
                  <li key={g.facilityId}>
                    <button
                      type="button"
                      onClick={() => f && openFacility(f)}
                      className="flex min-h-11 w-full items-center gap-2 rounded-md px-1 py-1 text-left text-sm transition-colors hover:bg-accent focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                    >
                      <span className="min-w-0 flex-1 text-foreground">
                        {g.landmark}
                      </span>
                      <IconArrowNarrowRight
                        className="size-4 shrink-0 text-muted-foreground"
                        aria-hidden="true"
                      />
                      <Badge variant="outline" className="shrink-0">
                        {g.exit}
                      </Badge>
                    </button>
                  </li>
                );
              })}
            </ul>
          </Card>
        </section>
      )}

      {/* ── 施設一覧 ──────────────────────────────── */}
      <section aria-label="施設一覧" className="px-4 pt-2">
        <div className="mb-2 flex items-baseline justify-between">
          <h2 className="text-sm font-semibold text-foreground">
            施設一覧
          </h2>
          <span className="text-xs text-muted-foreground" aria-live="polite">
            {results.length}件
          </span>
        </div>

        {results.length === 0 ? (
          <EmptyState
            icon={<IconSearch className="size-6" />}
            title="該当する施設がありません"
            description="カテゴリ・フロア・改札の条件をゆるめるか、検索語を変えてみてください。"
            headingLevel={3}
          />
        ) : (
          <ul className="space-y-2">
            {results.map((f) => {
              const Glyph = KIND_ICON[f.kind];
              return (
                <li key={f.id}>
                  <ListCard
                    onSelect={() => openFacility(f)}
                    selected={selected?.id === f.id && sheetOpen}
                    leading={
                      <span
                        className="flex size-10 items-center justify-center rounded-lg bg-secondary text-secondary-foreground"
                        aria-hidden="true"
                      >
                        <Icon icon={Glyph} size="md" />
                      </span>
                    }
                    title={f.name}
                    description={
                      <span className="flex flex-wrap items-center gap-x-2 gap-y-0.5">
                        <span className="inline-flex items-center gap-0.5">
                          <IconMapPin className="size-3.5" aria-hidden="true" />
                          {f.location}
                        </span>
                      </span>
                    }
                    tags={
                      <>
                        <Tag size="sm" variant="outline">
                          {f.floor}
                        </Tag>
                        <Tag size="sm" variant="outline">
                          {gateLabel(f.gateSide)}
                        </Tag>
                        {f.genre && (
                          <Tag size="sm" variant="default">
                            {f.genre}
                          </Tag>
                        )}
                      </>
                    }
                    status={statusFor(f)}
                    meta={
                      <span className="inline-flex items-center gap-0.5">
                        <IconWalk className="size-3.5" aria-hidden="true" />徒歩
                        {f.walkMinutes}分
                      </span>
                    }
                  />
                </li>
              );
            })}
          </ul>
        )}
      </section>

      {/* ── 構内図 affordance ─────────────────────── */}
      <section aria-label="構内図" className="px-4 pt-4">
        <Card className="overflow-hidden">
          <AspectRatio ratio={16 / 9}>
            <button
              type="button"
              className="group flex size-full flex-col items-center justify-center gap-2 bg-muted/50 transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
              aria-label="構内図を開く"
            >
              {/* 構内図のプレースホルダ（実機では SVG/画像マップに差し替え） */}
              <span
                className="flex size-12 items-center justify-center rounded-full bg-background text-muted-foreground shadow-sm"
                aria-hidden="true"
              >
                <Icon icon={IconMap2} size="lg" />
              </span>
              <span className="text-sm font-medium text-foreground">
                構内図を開く
              </span>
              <span className="text-xs text-muted-foreground">
                B1 / 1F / 2F・バリアフリー経路つき
              </span>
            </button>
          </AspectRatio>
        </Card>
      </section>

      {/* ── 施設詳細シート ────────────────────────── */}
      <FacilityDetailSheet
        facility={selected}
        open={sheetOpen}
        onOpenChange={setSheetOpen}
      />
    </main>
  );
}

// 駅構内ナビ — 東京駅の施設データ（デモ用の現実的なサンプル）
// All copy is real Japanese station vocabulary, not lorem ipsum.

export type CategoryId =
  | "all"
  | "exit"
  | "toilet"
  | "elevator"
  | "locker"
  | "shop"
  | "money"
  | "facility";

export interface Category {
  id: CategoryId;
  label: string;
  /** 一覧の見出し用の補足 */
  hint?: string;
}

export const CATEGORIES: Category[] = [
  { id: "all", label: "すべて" },
  { id: "exit", label: "出口・改札" },
  { id: "toilet", label: "トイレ" },
  { id: "elevator", label: "EV・ES" },
  { id: "locker", label: "コインロッカー" },
  { id: "shop", label: "店舗" },
  { id: "money", label: "お金まわり" },
  { id: "facility", label: "設備" },
];

export type FloorId = "B1" | "1F" | "2F";
export const FLOORS: { id: FloorId; label: string }[] = [
  { id: "B1", label: "B1" },
  { id: "1F", label: "1F" },
  { id: "2F", label: "2F" },
];

export type GateSide = "inside" | "outside";

/** ロッカー空き状況のサイズ別在庫 */
export interface LockerStock {
  size: "大" | "中" | "小";
  free: number;
  total: number;
}

/** 道案内の1ステップ（行き方）。RouteStops に流し込む。 */
export interface RouteStep {
  id: string;
  title: string;
  description?: string;
}

export type FacilityKind =
  | "exit"
  | "toilet"
  | "accessibleToilet"
  | "nursing"
  | "elevator"
  | "escalator"
  | "locker"
  | "shop"
  | "atm"
  | "ticketOffice"
  | "waitingRoom"
  | "smoking";

export interface Facility {
  id: string;
  /** 表示名 */
  name: string;
  /** カテゴリ（フィルタ用） */
  category: Exclude<CategoryId, "all">;
  /** 細かい種別（アイコン・詳細用） */
  kind: FacilityKind;
  /** フロア */
  floor: FloorId;
  /** 改札内 / 改札外 */
  gateSide: GateSide;
  /** 場所の短い説明（○番線付近 / ○口改札内 など） */
  location: string;
  /** 現在地からの目安（徒歩○分） */
  walkMinutes: number;
  /** 出口・店舗などの方面/ランドマーク（出口案内） */
  landmark?: string;
  /** 営業時間（店舗・窓口） */
  hours?: string;
  /** 店舗ジャンル */
  genre?: string;
  /** 店舗の営業状況 */
  open?: boolean;
  /** ロッカー空き状況 */
  locker?: LockerStock[];
  /** バリアフリー対応か */
  stepFree?: boolean;
  /** 行き方（バリアフリー経路ベース） */
  route: RouteStep[];
  /** 設備メモ */
  amenities?: string[];
}

