"use client";

import * as React from "react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@gunjo/ui";
import {
  Badge,
  Tag,
  Separator,
  RouteStops,
  Meter,
  Icon,
  type RouteStopItem,
} from "@gunjo/ui";
import { Button } from "@gunjo/ui";
import {
  IconMapPin,
  IconClock,
  IconWalk,
  IconWheelchair,
  IconMap2,
} from "@tabler/icons-react";
import type { Facility } from "./data";
import { KIND_ICON } from "./icons";

function gateLabel(side: Facility["gateSide"]) {
  return side === "inside" ? "改札内" : "改札外";
}

export function FacilityDetailSheet({
  facility,
  open,
  onOpenChange,
}: {
  facility: Facility | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}) {
  // Route → RouteStops items. The selected facility is the "current" goal; the
  // path leading to it is "completed" context, last step is where you arrive.
  const stops: RouteStopItem[] = React.useMemo(() => {
    if (!facility) return [];
    return facility.route.map((step, i) => ({
      id: step.id,
      seq: i + 1,
      title: step.title,
      description: step.description,
      status: i === facility.route.length - 1 ? "current" : "completed",
    }));
  }, [facility]);

  const KindGlyph = facility ? KIND_ICON[facility.kind] : null;

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="max-h-[88vh] overflow-y-auto rounded-t-2xl px-4 pb-8 pt-5 sm:max-w-none"
        closeLabel="閉じる"
      >
        {facility && (
          <>
            <SheetHeader className="space-y-2 text-left">
              <div className="flex items-start gap-3">
                <span
                  className="flex size-11 shrink-0 items-center justify-center rounded-xl bg-primary-subtle text-primary-subtle-foreground"
                  aria-hidden="true"
                >
                  {KindGlyph && <Icon icon={KindGlyph} size="md" />}
                </span>
                <div className="min-w-0 flex-1">
                  <SheetTitle className="text-lg leading-snug">
                    {facility.name}
                  </SheetTitle>
                  <SheetDescription className="mt-1 flex flex-wrap items-center gap-1.5">
                    <Badge variant="outline">{facility.floor}</Badge>
                    <Badge variant={facility.gateSide === "inside" ? "info" : "secondary"}>
                      {gateLabel(facility.gateSide)}
                    </Badge>
                    {facility.stepFree && (
                      <Badge variant="success" icon={<IconWheelchair className="size-3" />}>
                        バリアフリー対応
                      </Badge>
                    )}
                  </SheetDescription>
                </div>
              </div>
            </SheetHeader>

            {/* 場所・営業時間・距離 のメタ */}
            <dl className="mt-4 space-y-2.5 text-sm">
              <div className="flex gap-2">
                <dt className="flex w-20 shrink-0 items-center gap-1 text-muted-foreground">
                  <IconMapPin className="size-4" aria-hidden="true" /> 場所
                </dt>
                <dd className="flex-1 text-foreground">{facility.location}</dd>
              </div>
              <div className="flex gap-2">
                <dt className="flex w-20 shrink-0 items-center gap-1 text-muted-foreground">
                  <IconWalk className="size-4" aria-hidden="true" /> 目安
                </dt>
                <dd className="flex-1 text-foreground">
                  現在地から徒歩 約{facility.walkMinutes}分
                </dd>
              </div>
              {facility.hours && (
                <div className="flex gap-2">
                  <dt className="flex w-20 shrink-0 items-center gap-1 text-muted-foreground">
                    <IconClock className="size-4" aria-hidden="true" /> 営業時間
                  </dt>
                  <dd className="flex-1 text-foreground">{facility.hours}</dd>
                </div>
              )}
              {facility.genre && (
                <div className="flex gap-2">
                  <dt className="w-20 shrink-0 text-muted-foreground">ジャンル</dt>
                  <dd className="flex-1 text-foreground">{facility.genre}</dd>
                </div>
              )}
            </dl>

            {/* コインロッカー 空き状況（サイズ別 Meter） */}
            {facility.locker && (
              <section className="mt-5" aria-label="コインロッカー空き状況">
                <h3 className="mb-2 text-sm font-semibold text-foreground">
                  空き状況
                </h3>
                <div className="space-y-3 rounded-lg border bg-muted/30 p-3">
                  {facility.locker.map((l) => (
                    <Meter
                      key={l.size}
                      label={`${l.size}型ロッカー 空き ${l.free} / ${l.total}`}
                      value={l.free}
                      max={l.total}
                      direction="fill-is-good"
                      unit="個"
                    />
                  ))}
                </div>
              </section>
            )}

            {/* 設備タグ */}
            {facility.amenities && facility.amenities.length > 0 && (
              <section className="mt-5" aria-label="設備">
                <h3 className="mb-2 text-sm font-semibold text-foreground">設備</h3>
                <div className="flex flex-wrap gap-1.5">
                  {facility.amenities.map((a) => (
                    <Tag key={a} variant="outline">
                      {a}
                    </Tag>
                  ))}
                </div>
              </section>
            )}

            <Separator className="my-5" />

            {/* 行き方（バリアフリー経路） */}
            <section aria-label="行き方">
              <h3 className="mb-3 text-sm font-semibold text-foreground">
                行き方{facility.stepFree ? "（バリアフリー経路）" : ""}
              </h3>
              <RouteStops
                stops={stops}
                hideTimes
                statusLabels={{ current: "到着", completed: "経由" }}
              />
            </section>

            <div className="mt-6 flex gap-2">
              <Button variant="primary" className="flex-1" type="button">
                <IconMap2 className="size-4" aria-hidden="true" />
                構内図で見る
              </Button>
              <Button
                variant="outline"
                type="button"
                onClick={() => onOpenChange(false)}
              >
                閉じる
              </Button>
            </div>
          </>
        )}
      </SheetContent>
    </Sheet>
  );
}

